        <div class="card-body p-2" style="min-height: 200px;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight" />
            }

            @if (showForm)
            {
                <AddTaskForm OnSave="HandleSave" OnCancel="() => showForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100 mt-2" @onclick="() => showForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string Status { get; set; } = "";

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = [];

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveRight { get; set; }

    [Parameter]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnTaskCreated.InvokeAsync(data);
        showForm = false;
    }
}

@page "/board"
@rendermode InteractiveServer
@using sv_29628e21fad24116aa6573b74eeb4e05.Services
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />

    <BoardSearchBar SearchTerm="@searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="row g-3">
        <BoardColumn Status="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnMoveRight="id => MoveTask(id, "In Progress")"
                     OnTaskCreated="data => CreateTask(data, "To Do")" />

        <BoardColumn Status="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnMoveLeft="id => MoveTask(id, "To Do")"
                     OnMoveRight="id => MoveTask(id, "Done")"
                     OnTaskCreated="data => CreateTask(data, "In Progress")" />

        <BoardColumn Status="Done"
                     Tasks="GetFilteredTasks("Done")"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnMoveLeft="id => MoveTask(id, "In Progress")"
                     OnTaskCreated="data => CreateTask(data, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchTerm = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private void OnSearchChanged(string value)
    {
        searchTerm = value;
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                allTasks = allTasks
                    .Select(t => t.Id == taskId ? t with { Status = newStatus } : t)
                    .ToList();
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task CreateTask(
        (string Title, string Assignee, string Priority, DateTime DueDate) data,
        string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            // CreateTaskAsync returns a task with default status; override with the column's status
            var taskWithStatus = created with { Status = status };
            if (status != created.Status)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, status);
            }
            allTasks.Add(taskWithStatus);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

